1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (still life) unchanged", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a blinker from vertical to horizontal", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
26	    // Center cell (1,1) has 4 live neighbors → dies
27	    const input: [number, number][] = [
28	      [0, 0], [1, 0], [2, 0],
29	      [0, 1], [1, 1], [2, 1],
30	      [0, 2], [1, 2], [2, 2],
31	    ];
32	    const result = nextGeneration(input);
33	    expect(result).not.toContainEqual([1, 1]);
34	  });
35	  it("should bring a dead cell to life with exactly 3 neighbors (reproduction)", () => {
36	    // Dead cell (1,1) has exactly 3 live neighbors → becomes alive
37	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
38	    const result = nextGeneration(input);
39	    expect(result).toContainEqual([1, 1]);
40	  });
41	  it("should handle negative coordinates", () => {
42	    // Vertical blinker at negative coords → horizontal at gen 1
43	    const vertical: [number, number][] = [[-5, -5], [-5, -4], [-5, -3]];
44	    const horizontal: [number, number][] = [[-6, -4], [-5, -4], [-4, -4]];
45	    const result = nextGeneration(vertical);
46	    expect(result.sort()).toEqual(horizontal.sort());
47	  });
48	});
