export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(cellKey));
  const tallies = new Map<string, { cell: Cell; count: number }>();

  const allNeighbors = cells.flatMap(neighborsOf);
  for (const neighbor of allNeighbors) {
    const k = cellKey(neighbor);
    const prev = tallies.get(k)?.count ?? 0;
    tallies.set(k, { cell: neighbor, count: prev + 1 });
  }

  return [...tallies.values()]
    .filter(({ cell, count }) => survives(count, live.has(cellKey(cell))))
    .map(({ cell }) => cell);
}

